module.exports=[63974,a=>{a.v({Metadata:{title:"Gemini Turkiye | Premium Reiseerlebnisse in der Türkei",description:"Kuratierte Luxusreisen an der Schnittstelle der Zivilisationen. Entdecken Sie Kappadokien, Istanbul, Pamukkale und mehr mit Gemini Turkiye."},Nav:{home:"Startseite",about:"Über Uns",destinations:"Reiseziele",experiences:"Erlebnisse",contact:"Kontakt",bookNow:"Jetzt Buchen"},Hero:{tagline:"Wo Orient und Okzident sich Begegnen",subtitle:"Kuratierte Luxusreisen an der Schnittstelle der Zivilisationen",cta:"Planen Sie Ihre Reise",scrollDown:"Scrollen Sie, um zu entdecken"},Destinations:{sectionTitle:"Ikonische Reiseziele",sectionSubtitle:"Von antiken Ruinen bis zu Mittelmeerküsten — entdecken Sie die atemberaubendsten Orte der Türkei",viewAll:"Alle Reiseziele Anzeigen",learnMore:"Mehr Erfahren",cappadocia:{name:"Kappadokien",description:"Feenkamine und Heißluftballon-Abenteuer bei Sonnenaufgang über einer Mondlandschaft"},istanbul:{name:"Istanbul",description:"Wo Kontinente aufeinandertreffen — byzantinische Pracht begegnet osmanischer Herrlichkeit"},pamukkale:{name:"Pamukkale",description:"Baumwollschloss-Terrassen aus schimmerndem weißem Travertin und antiken Thermalquellen"},ephesus:{name:"Ephesos",description:"Wandeln Sie durch Jahrtausende der Geschichte in einer der am besten erhaltenen antiken Städte"},antalya:{name:"Antalya",description:"Türkisfarbene Küstenlinie trifft auf antike lykische Ruinen an der Mittelmeer-Riviera"},gobeklitepe:{name:"Göbeklitepe",description:"Der älteste Tempelkomplex der Welt — die Geschichte der menschlichen Zivilisation wird neu geschrieben"},bodrum:{name:"Bodrum",description:"Ägäische Eleganz mit weiß getünchten Dörfern, azurblauen Buchten und legendärem Nachtleben"}},Experiences:{sectionTag:"Erlebnisse",sectionTitle:"Kuratierte Erlebnisse",sectionSubtitle:"Zeitlose Erinnerungen, geschaffen mit Leidenschaft und Expertise",balloon:{name:"Heißluftballonfahrten",description:"Schweben Sie bei Sonnenaufgang über den Feenkaminen Kappadokiens und erleben Sie eine Landschaft, die die Vorstellungskraft herausfordert.",highlight:"Morgenflüge über Kappadokien"},gulet:{name:"Gulet-Kreuzfahrten",description:"Segeln Sie auf den türkisfarbenen Gewässern der Ägäis und des Mittelmeers an Bord einer traditionellen türkischen Holzgulet.",highlight:"Privatyacht entlang der Küste"},cultural:{name:"Kulturelle Reisen",description:"Erleben Sie die faszinierende Zeremonie der Drehenden Derwische und erkunden Sie lebendige Traditionen, die Jahrhunderte überspannen.",highlight:"Sema-Zeremonien und Kulturerbe-Touren"},food:{name:"Kulinarische Abenteuer",description:"Vom Gewürzbasar Istanbuls bis zu den Küchen Gazianteps — kosten Sie den reichen Teppich der türkischen Küche.",highlight:"Authentische türkische Gastronomie"},exploreMore:"Entdecken"},Stats:{years:"Jahre Erfahrung",tours:"Durchgeführte Touren",clients:"Zufriedene Kunden",destinations:"Reiseziele"},Testimonials:{sectionTag:"Bewertungen",sectionTitle:"Gästegeschichten",sectionSubtitle:"Hören Sie von Reisenden, die die Magie der Türkei mit uns erlebt haben",items:[{quote:"Ein absolut transformatives Erlebnis. Die Ballonfahrt über Kappadokien in der Morgendämmerung war der magischste Moment meines Lebens.",name:"Sarah Mitchell",location:"London, Großbritannien",tour:"Kappadokien Entdecker"},{quote:"Gemini Turkiye hat eine Reise kreiert, die jede Erwartung übertroffen hat. Die Liebe zum Detail war makellos.",name:"James Nakamura",location:"Tokio, Japan",tour:"Große Türkei-Rundreise"},{quote:"Von der Gulet-Kreuzfahrt bis zu den Drehenden Derwischen — jeder Moment war bis zur Perfektion kuratiert. Wirklich unvergesslich.",name:"Marie Dubois",location:"Paris, Frankreich",tour:"Kulturerbe-Reise"},{quote:"Die kulinarische Tour durch Istanbul war eine Offenbarung. Wir entdeckten Aromen und Traditionen, von deren Existenz wir nichts wussten.",name:"Marco Rossi",location:"Mailand, Italien",tour:"Kulinarische Entdeckungsreise"}]},CTA:{tagline:"Starten Sie Ihr Abenteuer",title:"Planen Sie Ihre Traumreise",subtitle:"Lassen Sie uns ein unvergessliches türkisches Erlebnis gestalten, das speziell für Sie maßgeschneidert ist",button:"Planung Starten"},About:{heroTitle:"Unsere Geschichte",heroSubtitle:"Seit 2010 gestalten wir außergewöhnliche Türkei-Erlebnisse",storyTitle:"Eine Leidenschaft für die Türkei",storyP1:"Gemini Turkiye entstand aus einer tiefen Liebe zum reichen Mosaik aus Kulturen, Landschaften und Traditionen der Türkei. Gegründet im Jahr 2010, haben wir uns zum Ziel gesetzt, die authentische Schönheit dieses außergewöhnlichen Landes mit anspruchsvollen Reisenden aus aller Welt zu teilen.",storyP2:"Unser Team erfahrener Reisedesigner verbindet tiefgehendes lokales Wissen mit erstklassiger Gastfreundschaft, um Reisen zu gestalten, die gewöhnlichen Tourismus übertreffen. Jede Reiseroute wird sorgfältig zusammengestellt, um sowohl die verborgenen Schätze als auch die ikonischen Wahrzeichen der Türkei zu enthüllen.",storyP3:"Von den Feenkaminen Kappadokiens bis zu den azurblauen Gewässern der Ägäis, von den lebhaften Basaren Istanbuls bis zu den antiken Ruinen von Ephesos — wir sorgen dafür, dass jeder Moment Ihrer Türkei-Reise außergewöhnlich ist.",valuesTitle:"Unsere Werte",values:{luxury:{title:"Kompromissloser Luxus",description:"Jedes Detail wird kuratiert, um ein Erlebnis auf höchstem Niveau zu bieten"},authenticity:{title:"Kulturelle Authentizität",description:"Wir verbinden Sie durch authentische lokale Erlebnisse mit dem lebendigen Erbe der Türkei"},excellence:{title:"Exzellenter Service",description:"Unser engagiertes Team sorgt für nahtlose Reisen von der ersten Anfrage bis zum letzten Abschied"}}},Contact:{heroTitle:"Kontaktieren Sie Uns",heroSubtitle:"Beginnen Sie Ihre Türkei-Reise mit einem Gespräch",formTitle:"Senden Sie Uns eine Nachricht",form:{name:"Ihr Name",email:"E-Mail-Adresse",phone:"Telefonnummer",interest:"Tour-Interesse",interests:{select:"Wählen Sie einen Tourtyp",cappadocia:"Kappadokien Entdecker",istanbul:"Istanbul Entdeckung",gulet:"Gulet-Kreuzfahrt",cultural:"Kulturerbe",culinary:"Kulinarisches Abenteuer",custom:"Individuelle Reise"},message:"Ihre Nachricht",submit:"Nachricht Senden",sending:"Wird gesendet...",success:"Nachricht erfolgreich gesendet! Wir melden uns bald bei Ihnen.",error:"Etwas ist schiefgelaufen. Bitte versuchen Sie es erneut."},infoTitle:"Kontaktdaten",info:{addressTitle:"Adresse",address:"Merkez mah. Halaskargazi cad.\nNo 175 Kat:8 Şişli – Istanbul Turkey",companyInfo:"Gemini Turizm Tic. A.S.\nŞişli VD. 3910312785",phoneTitle:"Telefon",phone:"+90 212 123 45 67",emailTitle:"E-Mail",email:"info@geminiturkiye.com",hoursTitle:"Öffnungszeiten",hours:"Mo - Sa: 09:00 - 18:00"},followTitle:"Folgen Sie Uns"},DestinationsPage:{heroTitle:"Entdecken Sie die Türkei",heroSubtitle:"Ein Land, in dem antike Geschichte auf atemberaubende Naturschönheit trifft",explore:"Entdecken"},ExperiencesPage:{heroTitle:"Außergewöhnliche Erlebnisse",heroSubtitle:"Handgefertigte Reisen, die Erinnerungen fürs Leben schaffen",bookNow:"Dieses Erlebnis Buchen"},Footer:{description:"Kuratierte Luxus-Reiseerlebnisse in der gesamten Türkei. Entdecken Sie die Schnittstelle der Zivilisationen mit erfahrenen lokalen Reiseführern.",quickLinks:"Schnellzugriff",company:"Unternehmen",contactUs:"Kontaktieren Sie Uns",newsletter:"Newsletter",newsletterText:"Abonnieren Sie exklusive Reiseeinblicke und Angebote",emailPlaceholder:"Ihre E-Mail-Adresse",subscribe:"Abonnieren",rights:"Alle Rechte vorbehalten.",privacy:"Datenschutzrichtlinie",terms:"Nutzungsbedingungen"}})}];

